const CACHES={models:new Map,availability:new Map},TTL={models:300*1e3,availability:30*1e3};export function getCachedModels(providerId){const cached=CACHES.models.get(providerId);return cached&&Date.now()-cached.timestamp<TTL.models?cached.models:null}export function setCachedModels(providerId,models){CACHES.models.set(providerId,{models,timestamp:Date.now()})}export function getCachedAvailability(providerId){const cached=CACHES.availability.get(providerId);return cached&&Date.now()-cached.timestamp<TTL.availability?cached.available:null}export function setCachedAvailability(providerId,available){CACHES.availability.set(providerId,{available,timestamp:Date.now()})}export function clearProviderCache(providerId){providerId?(CACHES.models.delete(providerId),CACHES.availability.delete(providerId)):(CACHES.models.clear(),CACHES.availability.clear())}
